import {
  forwardRef,
  type ElementType,
  type MouseEvent as ReactMouseEvent,
} from 'react';
import { useIntl } from 'react-intl';

import { CopyIcon } from '@dynatrace/strato-icons';
import {
  getEnvironmentId,
  getAppName,
  getAppId,
  getCurrentUserDetails,
} from '@dynatrace-sdk/app-environment';

import { ButtonProps, Button } from '../../../../buttons/button/Button.js';
import { Text } from '../../../../typography/text/Text.js';
import { TextEllipsis } from '../../../../typography/text-ellipsis/TextEllipsis.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';

/**
 * The copy permissions button shown in the SegmentSelector if the user doesn't have permissions to read segments.
 * @internal
 */
export const CopyPermissionsButton = forwardRef<
  HTMLButtonElement,
  Pick<ButtonProps<ElementType>, 'variant' | 'color'>
>(({ variant, color }, forwardedRef) => {
  const intl = useIntl();

  const environmentId = getEnvironmentId();
  const appName = getAppName();
  const appId = getAppId();
  const { id, email } = getCurrentUserDetails();

  const clipboardText = `Your assigned access control policies are missing the following permissions:\nMissing permissions: storage:filter-segments:read;\nEnvironment: ${environmentId}\nApp name: ${appName}\nApp ID: ${appId}\nUser email: ${email}\nUser ID: ${id}`;

  return (
    <Button
      variant={variant}
      ref={forwardedRef}
      color={color}
      onClick={(e: ReactMouseEvent) => {
        e.stopPropagation();
        navigator.clipboard.writeText(clipboardText).catch(() => {
          // For now, we silently ignore clipboard write errors.
        });
      }}
    >
      <Button.Prefix>
        <CopyIcon />
      </Button.Prefix>
      <Text textStyle="base-emphasized">
        <TextEllipsis>
          {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.copyDetailsButton)}
        </TextEllipsis>
      </Text>
    </Button>
  );
});
